const patterns = $('Analyze Page Patterns').first().json.patterns;
const stories = $('List All Pages').first().json.stories;

const issues = [];
for (const story of stories) {
  const content = story.content;
  if (!content || !content.section) continue;
  const sections = Array.isArray(content.section) ? content.section : [];

  // Check for missing CTA
  const hasCta = sections.some(s => s.component === 'cta');
  if (!hasCta && sections.length > 2) {
    issues.push({ story: story.full_slug, issue: 'Missing CTA section', severity: 'warning' });
  }

  // Check for sparse pages
  if (sections.length < 2) {
    issues.push({ story: story.full_slug, issue: `Only ${sections.length} section(s)`, severity: 'warning' });
  }

  // Check for duplicate heroes
  const heroCount = sections.filter(s => s.component === 'hero').length;
  if (heroCount > 1) {
    issues.push({ story: story.full_slug, issue: `${heroCount} hero sections (should be 1)`, severity: 'error' });
  }
}

return [{
  json: {
    totalPages: stories.length,
    totalIssues: issues.length,
    componentFrequency: patterns.componentFrequency,
    pageArchetypes: patterns.pageArchetypes,
    issues
  }
}];

